// Data/Configuration/ActionEntityConfiguration.cs
public class ActionEntityConfiguration : IEntityTypeConfiguration<ActionEntity>
{
    public void Configure(EntityTypeBuilder<ActionEntity> entity)
    {
        entity.ToTable("Actions", "actions");
        entity.HasKey(e => e.Id);
        entity.ConfigureTrackedEntity();
        entity.ConfigureTenantEntity();

        // Properties
        entity.Property(e => e.ReferenceNumber)
            .HasMaxLength(50)
            .IsRequired();
        entity.Property(e => e.Status)
            .HasConversion<string>()    // ADR-0004: enum stored as string
            .HasMaxLength(50)
            .IsRequired();
        entity.Property(e => e.Priority)
            .HasConversion<string>()
            .HasMaxLength(50)
            .IsRequired();
        entity.Property(e => e.Version).IsConcurrencyToken();

        // Soft delete
        entity.Property(e => e.IsDeleted).HasDefaultValue(false);
        entity.HasQueryFilter(e => !e.IsDeleted);

        // Relationships
        entity.HasOne(e => e.WorkflowDefinition)
            .WithMany(w => w.Actions)
            .HasForeignKey(e => e.WorkflowDefinitionId)
            .OnDelete(DeleteBehavior.Restrict);

        entity.HasOne(e => e.CurrentState)
            .WithMany()
            .HasForeignKey(e => e.CurrentStateId)
            .OnDelete(DeleteBehavior.SetNull);

        // Indexes
        entity.HasIndex(e => new { e.TenantId, e.ReferenceNumber }).IsUnique();
        entity.HasIndex(e => e.Status);
    }
}

// Data/Configuration/SharedConfiguration.cs
public static class SharedConfiguration
{
    public static void ConfigureTrackedEntity<T>(this EntityTypeBuilder<T> entity)
        where T : TrackedEntity
    {
        entity.Property(e => e.CreatedDate).IsRequired();
        entity.Property(e => e.CreatedById).IsRequired();
    }

    public static void ConfigureTenantEntity<T>(this EntityTypeBuilder<T> entity)
        where T : class, ITenantEntity
    {
        // Marks TenantId as required. Each entity configuration MUST explicitly
        // configure the tenant relationship if a navigation property exists,
        // to avoid EF Core creating shadow FK columns.
        entity.Property(e => e.TenantId).IsRequired();
    }
}

// Correct — explicit delete behavior on every FK
entity.HasOne(e => e.WorkflowDefinition)
    .WithMany(w => w.Actions)
    .HasForeignKey(e => e.WorkflowDefinitionId)
    .OnDelete(DeleteBehavior.Restrict);

// Wrong — missing OnDelete (EF Core defaults vary and are unsafe)
entity.HasOne(e => e.WorkflowDefinition)
    .WithMany(w => w.Actions)
    .HasForeignKey(e => e.WorkflowDefinitionId);

// Unique composite — tenant-scoped uniqueness
entity.HasIndex(e => new { e.TenantId, e.ReferenceNumber }).IsUnique();

// Filtered index — only index active records
entity.HasIndex(e => e.Code)
    .HasFilter("\"IsActive\" = true");

// Covering index for common query pattern
entity.HasIndex(e => new { e.TenantId, e.Status });

// Correct — C# enum with HasConversion<string>()
entity.Property(e => e.Status)
    .HasConversion<string>()
    .HasMaxLength(50)
    .IsRequired();

// Wrong — string property without enum conversion
entity.Property(e => e.Status)
    .HasMaxLength(50)
    .IsRequired();

// Entity property
public string[]? Tags { get; set; }

// EF Configuration
entity.Property(e => e.Tags)
    .HasColumnType("text[]");

// Simple default
entity.Property(e => e.IsActive).HasDefaultValue(true);
entity.Property(e => e.IsDeleted).HasDefaultValue(false);

// SQL expression default (timestamps, empty JSON, generated values)
entity.Property(e => e.CreatedDate).HasDefaultValueSql("now()");
entity.Property(e => e.Configuration).HasDefaultValueSql("'{}'::jsonb");

// Data/Configuration/WorkflowDefinitionTranslationConfiguration.cs
public class WorkflowDefinitionTranslationConfiguration : IEntityTypeConfiguration<WorkflowDefinitionTranslation>
{
    public void Configure(EntityTypeBuilder<WorkflowDefinitionTranslation> entity)
    {
        entity.ToTable("WorkflowDefinitionTranslations", "actions");
        entity.HasKey(e => e.Id);
        entity.ConfigureTrackedEntity();
        entity.ConfigureTenantEntity();

        entity.Property(e => e.Name).HasMaxLength(250).IsRequired();
        entity.Property(e => e.Description).HasColumnType("text");
        entity.Property(e => e.LanguageId).IsRequired();

        // Composite unique: one translation per entity per language per tenant
        entity.HasIndex(e => new { e.WorkflowDefinitionId, e.LanguageId, e.TenantId }).IsUnique();

        entity.HasOne<WorkflowDefinition>()
            .WithMany(w => w.Translations)
            .HasForeignKey(e => e.WorkflowDefinitionId)
            .OnDelete(DeleteBehavior.Cascade);

        entity.HasOne(e => e.Language)
            .WithMany()
            .HasForeignKey(e => e.LanguageId)
            .OnDelete(DeleteBehavior.Restrict);
    }
}

// Data/ActionsDbContext.cs
protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    modelBuilder.HasDefaultSchema("actions");

    // Auto-discover and apply all IEntityTypeConfiguration<T> classes in this assembly
    modelBuilder.ApplyConfigurationsFromAssembly(typeof(ActionsDbContext).Assembly);
}
